class Solution {
    public int numSub(String s) {
        int mod = 1000000007;
        int count = 0;
        int consecutiveOnes = 0;

        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '1') {
                consecutiveOnes++;
                count = (count + consecutiveOnes) % mod;
            } else {
                consecutiveOnes = 0;
            }
        }

        return count;
    }
}

